// Render programme
function renderProgram(data){
  const $root = document.getElementById("program");

  function romanToInt(s){
    if (!s) return NaN;
    const map = {I:1, V:5, X:10, L:50, C:100, D:500, M:1000};
    let total = 0, prev = 0;
    for (let i = s.length - 1; i >= 0; i--) {
      const val = map[s[i].toUpperCase()] || 0;
      total += val < prev ? -val : val;
      prev = val;
    }
    return total;
  }

  function panelIndex(panelLabel){
    if (!panelLabel) return Number.POSITIVE_INFINITY;
    const m = panelLabel.match(/Panel\s+([IVXLCDM]+)\b/i);
    if (!m) return Number.POSITIVE_INFINITY;
    const n = romanToInt(m[1]);
    return Number.isNaN(n) ? Number.POSITIVE_INFINITY : n;
  }

  $root.innerHTML = data.map(day => {
    const groups = Object.values(
      day.items.reduce((acc, it) => {
        const key = `${it.panel ?? ""}||${it.time ?? ""}||${it.chair ?? ""}`;
        if (!acc[key]) acc[key] = { panel: it.panel || "", time: it.time || "", chair: it.chair || "", talks: [] };
        acc[key].talks.push(it);
        return acc;
      }, {})
    );

    groups.forEach((g, i) => g._idx = i);

    groups.sort((a, b) => {
      const A = panelIndex(a.panel);
      const B = panelIndex(b.panel);
      if (A === B) return a._idx - b._idx;
      return A - B;
    });

    function posNumber(v) {
      if (v === 0 || v === "0") return 0;
      if (v == null || v === "") return Number.POSITIVE_INFINITY;
      const n = parseFloat(String(v).replace(",", "."));
      return Number.isNaN(n) ? Number.POSITIVE_INFINITY : n;
    }

    groups.forEach(g => {
      g.talks.forEach((t, ti) => t._idx = ti);
      g.talks.sort((t1, t2) => {
        const p1 = posNumber(t1.position);
        const p2 = posNumber(t2.position);
        if (p1 === p2) return t1._idx - t2._idx;
        return p1 - p2;
        });
    });
    
      if (!$root.dataset.closeHandlerAttached) {
    $root.addEventListener("click", (e) => {
      const btn = e.target.closest(".details-close");
      if (!btn) return;
      const d = btn.closest("details");
      if (d) {
        d.open = false;
        const s = d.querySelector("summary");
        if (s) s.focus();y
      }
    });
    $root.dataset.closeHandlerAttached = "true";
    }

    const groupsHTML = groups.map(g => `
      <div class="panel">
      <p>
        ${g.time ? ` ${g.time}` : ""} 
        <span class="panel-name">${g.panel}</span>${g.chair ? ` (chair: ${g.chair})` : ""}
      </p>
      <ul class="panel-speaker">
        ${g.talks.map(t => `
            <details>
              <summary>
                <span class="speaker">${t.speaker}</span>:
                <span class="presentation-title">${t.title}</span>
              </summary>
              <p class="abstract">${t.abstract}</p>
              ${t.bio
                ? `<p class="bio">${t.bio} <button class="details-close" type="button" aria-label="Close this talk">×</button></p>`
                : ""
              }
            </details>
        `).join("")}
      </ul>
      </div>
    `).join("");

    return `
      <section class="day">
        <h2>${day.dayHeading}</h2>
        <div class="day-location"><a href="info" data-route>@${day.location}</a></div>
        ${groupsHTML}
      </section>
    `;
  }).join("");
}


// Map files
const routes = {
  "/about": "about.html",
  "/programme": "programme.html",
  "/keynote": "keynote.html",
  "/info": "info.html",
  "/credits": "credits.html",
  "/archive": "archive.html",
  "/koncept": "koncpet.html",
  "/program": "program.html",
  "/keynote-si": "keynote-si.html",
  "/info-si": "info-si.html",
  "/kolofon": "kolofon.html",
  "/arhiv": "arhiv.html",
  "/": null
};

function getContainer() {
  return document.querySelector(".content");
}

function currentPath() {
  // Prefer hash (hash routing works on GitHub Pages), fallback to "/"
  return location.hash.replace(/^#/, "") || "/";
}

async function loadRoute(path) {
  const target = routes[path] ?? null;
  const container = getContainer();
  if (!container) return;
  if (!target) {
    // No partial for this path -> keep whatever is in .content (or clear it)
    // container.innerHTML = ""; // uncomment if you want a blank home
    return;
  }

  try {
    const html = await (await fetch(target)).text();
    container.innerHTML = html;
    // Hydrate AFTER injection
    if (path === "/programme" && typeof renderProgram === "function") {
      renderProgram(window.programData);
    }

    const main = document.querySelector("main");
    if (main) {
    main.scrollIntoView({ behavior: "instant", block: "start" });
    } else {
    container.scrollIntoView({ behavior: "instant", block: "start" });
    }
  } catch (err) {
    container.innerHTML = "<p>Couldn't load this section.</p>";
    console.error(err);
  }
}

// Helper: normalize path
function normalizePath(p) {
  if (!p) return "/";
  const url = new URL(p, location.origin);
  return url.pathname.replace(/\/+$/, "") || "/";
}

// Helper: current route from hash (GitHub Pages friendly)
function currentPath() {
  const raw = (location.hash || "").replace(/^#/, "") || "/";
  return normalizePath(raw);
}

// Apply .is-active to the matching data-route link
function setActiveLink(path) {
  // homepage should highlight ABOUT
  if (path === "/") path = "/about";

  document.querySelectorAll(".nav-menu a[data-route]").forEach(a => {
    const linkPath = normalizePath(a.getAttribute("href"));
    a.classList.toggle("is-active", linkPath === path);
  });
}

// Intercept nav clicks on data-route links
document.addEventListener("click", (e) => {
  const a = e.target.closest("a[data-route]");
  if (!a) return;

  e.preventDefault();
  const path = normalizePath(a.getAttribute("href"));
  // use hash routing so deep-links work on static hosting
  if (location.hash.replace(/^#/, "") !== path) {
    location.hash = path;            // triggers hashchange -> loadRoute + setActiveLink
  } else {
    // if already on the same hash, still update UI
    setActiveLink(path);
    loadRoute(path);
  }
});

// Back/forward
window.addEventListener("hashchange", () => {
  const path = currentPath();
  setActiveLink(path);
  loadRoute(path);
});

// Initial render — ensure only the correct one is active
(function init() {
  // remove accidental is-active from any non-matching links
  document.querySelectorAll(".nav-menu a[data-route].is-active").forEach(a => {
    const linkPath = normalizePath(a.getAttribute("href"));
    const shouldBeActive =
      (location.hash === "" && linkPath === "/about") ||
      (location.hash !== "" && linkPath === currentPath());
    if (!shouldBeActive) a.classList.remove("is-active");
  });

  setActiveLink(currentPath());
  loadRoute(currentPath());
})();

document.addEventListener("DOMContentLoaded", () => {
  const burger = document.querySelector(".hamburger");
  const menu = document.querySelector("#nav-menu");
  if (!burger || !menu) return;

  burger.addEventListener("click", () => {
    const open = menu.classList.toggle("open");
    burger.classList.toggle("active", open);
    burger.setAttribute("aria-expanded", String(open));
  });

  menu.addEventListener("click", (e) => {
    if (e.target.closest("a[data-route]")) {
      menu.classList.remove("open");
      burger.classList.remove("active");
      burger.setAttribute("aria-expanded", "false");
    }
  })
});